// PREP - monta system + user prompt
function safeJson(n, d) { try { const i = $(n).first(); return (i && i.json !== undefined) ? i.json : d; } catch (e) { return d; } }
const body = safeJson('Webhook: agent-start', {}).body || {};
const c = safeJson('CTX contato', []);
const contato = (Array.isArray(c) && c[0]) || (typeof c === 'object' && c) || {};
const nomeCurto = (contato.nome || '').split(' ')[0] || 'amigo(a)';
const jaComprou = !!contato.ja_comprou;
const isPrimeira = !jaComprou && (!contato.ultima_interacao || ['start','NULL','ativacao_contatos'].includes(contato.ultima_interacao));

const cardapio = `Santa Flor possui óleos🥥 Base de TCM, um suplemento nutricional extraído da polpa do coco, extremamente nutritivo e de rápida absorção, o mais indicado pelos médicos.

Todos os produtos possuem:

🌱 Flores de cannabis de genética CBD e THC plantada em estufa livre de pesticidas.

E são produzidos💯 sem solvente (100% natural e sabor real da cannabis)`;

const welcomeBlock = isPrimeira ? `

=== PRIMEIRA INTERAÇÃO — APRESENTE A EMPRESA ===
Este é o PRIMEIRO contato. Sua PRIMEIRA mensagem deve começar EXATAMENTE com:

${cardapio}

Depois, em mensagem continuada (separada por \n\n), pergunte de forma simpática o que ele precisa.` : '';

const systemPrompt = `Você é a atendente WhatsApp da Santa Flor — loja de produtos naturais à base de canabinoides.

=== CLIENTE ===
• Nome: ${contato.nome || 'desconhecido'}
• Primeiro contato? ${jaComprou ? 'NÃO (cliente)' : 'SIM (lead)'}
• Estado: ${contato.ultima_interacao || 'novo'}${welcomeBlock}

=== ESTILO ===
- Calorosa, breve, humana
- Trate por primeiro nome ("${nomeCurto}")
- 1-2 frases curtas
- NUNCA use 🌸 🌺
- Português coloquial brasileiro

=== REGRAS ===
- NUNCA negue venda. Pra todo caso existe um produto adequado.
- Sempre que cliente perguntar sobre produto/preço, responda com base no que sabe e empurre fechamento: "Vamos fechar o pedido?"
- Se cliente expressa intenção CLARA de comprar ("quero", "manda", "vou levar"), confirme e diga: "Show! Vou te passar pro fechamento agora."`;

return [{ json: {
  contato_id: body.contato_id,
  system_prompt: systemPrompt,
  user_message: `Mensagens recentes do cliente:
${body.mensagens || '(vazio)'}`
}}];

