// FORMAT OUTPUT defensivo
let out = '';
try {
  const r = $input.first().json;
  out = r.choices?.[0]?.message?.content || r.output || r.text || '';
  if (typeof out === 'object') out = JSON.stringify(out);
} catch (e) {}
out = String(out || '').trim();
if (!out) out = 'Oi! Tô com uma instabilidade aqui, pode repetir sua mensagem? 🙏';
let contatoId = null;
try { contatoId = $('Webhook: agent-start').first().json.body.contato_id; } catch (e) {}
return [{ json: { resposta_texto: out, contato_id: contatoId } }];
